const raw = $env.MONITOR_SERVERS_JSON || '[]';
let servers;
try { servers = JSON.parse(raw); } catch (e) { servers = []; }
return servers.map(s => ({ json: s }));

// Threshold-based alerts with per-key 30-min debounce.
const staticData = $getWorkflowStaticData('global');
staticData.alertedAt = staticData.alertedAt || {};

const DEBOUNCE_MS = 30 <b> 60 </b> 1000; // 30 min
const now = Date.now();
function shouldAlert(key) {
  const last = staticData.alertedAt[key] || 0;
  if (now - last < DEBOUNCE_MS) return false;
  staticData.alertedAt[key] = now;
  return true;
}
function clearAlert(key) {
  delete staticData.alertedAt[key];
}

const messages = [];

for (const item of $input.all()) {
  const data = item.json;
  const server = data.server || 'unknown';
  const t = data.thresholds || { disk_pct: 80, mem_pct: 85, load_1m: 5 };

  // Disk
  for (const fs of (data.disk || [])) {
    const key = <code>${server}::disk::${fs.mount}</code>;
    if (fs.used_pct >= t.disk_pct) {
      if (shouldAlert(key)) {
        const free_g = (fs.available_bytes / (1024*<b>3)).toFixed(1);
        const total_g = (fs.total_bytes / (1024</b><b>3)).toFixed(0);
        messages.push(<code>💾 </b>${server}<b> — disk \</code>${fs.mount}\<code> ${fs.used_pct}% to'la (${free_g}G qoldi / ${total_g}G)</code>);
      }
    } else {
      clearAlert(key);
    }
  }

  // Memory
  const m = data.memory || {};
  if (m.used_pct >= t.mem_pct) {
    const key = <code>${server}::mem</code>;
    if (shouldAlert(key)) {
      const used_g = (m.used_bytes / (1024</b><b>3)).toFixed(1);
      const total_g = (m.total_bytes / (1024</b><b>3)).toFixed(0);
      messages.push(<code>🧠 </b>${server}<b> — RAM ${m.used_pct}% band (${used_g}G/${total_g}G)</code>);
    }
  } else {
    clearAlert(<code>${server}::mem</code>);
  }

  // Load
  const l = data.load || {};
  if (l['1m'] && l['1m'] >= t.load_1m) {
    const key = <code>${server}::load</code>;
    if (shouldAlert(key)) {
      messages.push(<code>⚡️ </b>${server}<b> — load avg yuqori: 1m=${l['1m']} 5m=${l['5m']} 15m=${l['15m']}</code>);
    }
  } else {
    clearAlert(<code>${server}::load</code>);
  }
}

if (!messages.length) return [];
return [{ json: { message: '🟠 </b>Resurs ogohlantirishi*\n\n' + messages.join('\n') } }];
